              letterSpacing: "0.16em",
              textTransform: "uppercase",
              color: "#94a3b8",
              opacity: labelEnter,
            }}
          >
            {label}
          </div>
        </div>
      </div>
      <div
        style={{
          position: "absolute",
          left: padX,
