          bottom: padY,
          height: 6,
          background: "rgba(15,23,42,.9)",
          border: "1px solid rgba(34,211,238,.22)",
        }}
      >
        <div
          style={{
            width: `${animatedProgress}%`,
            height: "100%",
            background: "linear-gradient(90deg, rgba(34,211,238,.25), #22d3ee)",
