// Engenharia / Chart Data / Progress Bars / 9:16 Shorts
// Importado pelo Template Studio.
"use client";

import {
  AbsoluteFill,
  interpolate,
  useCurrentFrame,
  useVideoConfig,
} from "remotion";

type EngineeringProgressItem = {
  label: string;
  value: number | string;
  color?: string;
  meta?: string;
};

type EngineeringProgressBarsProps = {
  title?: string;
  subtitle?: string;
  items?: EngineeringProgressItem[];
  unit?: string;
  panelLabel?: string;
  statusText?: string;
  location?: string;
  projectCode?: string;
  primaryColor?: string;
  secondaryColor?: string;
  accentColor?: string;
  backgroundColor?: string;
  durationInFrames?: number | string;
};

const toNumber = (value: unknown, fallback: number) => {
  const parsed = Number(value);
  return Number.isFinite(parsed) ? parsed : fallback;
};

const defaultItems: EngineeringProgressItem[] = [
  { label: "FUNDAÇÃO", value: 92, color: "#22d3ee", meta: "Base estrutural" },
  { label: "ESTRUTURA", value: 86, color: "#facc15", meta: "Concreto armado" },
  { label: "VEDAÇÃO", value: 74, color: "#14b8a6", meta: "Alvenaria" },
  { label: "INSTALAÇÕES", value: 63, color: "#38bdf8", meta: "Elétrica / hidráulica" },
  { label: "ACABAMENTO", value: 48, color: "#a3e635", meta: "Finalização" },
];

const fallbackColors = [
  "#22d3ee",
  "#facc15",
  "#14b8a6",
  "#38bdf8",
  "#a3e635",
  "#fb923c",
  "#818cf8",
];

export default function EngineeringProgressBars({
  title = "AVANÇO POR ETAPA",
  subtitle = "Painel técnico de execução da obra em tempo real",
  items = defaultItems,
  unit = "%",
  panelLabel = "CONTROLE DE PRODUÇÃO",
  statusText = "MONITORAMENTO ATIVO",
  location = "SETOR ESTRUTURAL A-03",
  projectCode = "ENG-7182",
  primaryColor = "#22d3ee",
  secondaryColor = "#0f766e",
  accentColor = "#facc15",
  backgroundColor = "#05070d",
  durationInFrames = 90,
}: EngineeringProgressBarsProps) {
  const frame = useCurrentFrame();
  const { width, height } = useVideoConfig();

  const isVertical = height > width;
  const data = items.length > 0 ? items : defaultItems;
  const animationDuration = Math.max(1, toNumber(durationInFrames, 90));

  const entrance = interpolate(frame, [0, 24], [0, 1], {
    extrapolateLeft: "clamp",
    extrapolateRight: "clamp",
  });

  const scanY = interpolate(frame % 130, [0, 130], [-12, 112]);

  const values = data.map((item) =>
    Math.max(0, Math.min(100, toNumber(item.value, 0)))
  );

  const averageValue =
    values.reduce((sum, value) => sum + value, 0) / Math.max(1, values.length);

  const titleSize = isVertical ? width * 0.052 : height * 0.052;
  const subtitleSize = isVertical ? width * 0.03 : height * 0.026;

  const panelWidth = isVertical ? width * 0.9 : width * 0.62;
  const panelHeight = isVertical ? height * 0.52 : height * 0.62;

  return (
    <AbsoluteFill
      style={{
        backgroundColor,
        overflow: "hidden",
        color: "#e5f7ff",
        fontFamily:
          "Inter, system-ui, -apple-system, BlinkMacSystemFont, Segoe UI, sans-serif",
        opacity: entrance,
      }}
    >
      <div
        style={{
          position: "absolute",
          inset: 0,
          backgroundImage: `
            linear-gradient(rgba(34,211,238,0.08) 1px, transparent 1px),
            linear-gradient(90deg, rgba(34,211,238,0.08) 1px, transparent 1px),
            linear-gradient(rgba(250,204,21,0.04) 1px, transparent 1px),
            linear-gradient(90deg, rgba(250,204,21,0.04) 1px, transparent 1px)
          `,
          backgroundSize: "42px 42px, 42px 42px, 168px 168px, 168px 168px",
        }}
      />

      <div
        style={{
          position: "absolute",
          inset: 0,
          background:
            "radial-gradient(circle at center, rgba(15,23,42,0.22) 0%, rgba(2,6,23,0.96) 78%)",
        }}
      />

      <div
        style={{
          position: "absolute",
          left: 0,
          right: 0,
          top: `${scanY}%`,
          height: 2,
          background: `linear-gradient(90deg, transparent, ${primaryColor}, transparent)`,
          opacity: 0.38,
          filter: `drop-shadow(0 0 12px ${primaryColor})`,
        }}
      />

      <div
        style={{
          position: "absolute",
          top: isVertical ? 58 : 46,
          left: isVertical ? 42 : 68,
          right: isVertical ? 42 : 68,
          transform: `translateY(${interpolate(entrance, [0, 1], [-18, 0])}px)`,
        }}
      >
        <div
          style={{
            display: "inline-flex",
            alignItems: "center",
            gap: 12,
            padding: "10px 16px",
            border: `1px solid rgba(34,211,238,0.42)`,
            background: "rgba(8,13,24,0.82)",
            clipPath:
              "polygon(0 0, calc(100% - 14px) 0, 100% 14px, 100% 100%, 14px 100%, 0 calc(100% - 14px))",
            boxShadow: "0 0 24px rgba(34,211,238,0.14)",
          }}
        >
          <div
            style={{
              width: 10,
              height: 10,
              background: accentColor,
              boxShadow: `0 0 12px ${accentColor}`,
            }}
          />
          <span
            style={{
              fontSize: isVertical ? 16 : 15,
              letterSpacing: 3,
              color: "rgba(255,255,255,0.78)",
              fontWeight: 800,
              textTransform: "uppercase",
            }}
          >
            {projectCode}
          </span>
        </div>

        <h1
          style={{
            margin: "20px 0 8px",
            fontSize: titleSize,
            lineHeight: 1,
            fontWeight: 950,
            letterSpacing: -1.4,
            textTransform: "uppercase",
            color: "white",
            textShadow: "0 0 24px rgba(34,211,238,0.28)",
          }}
        >
          {title}
        </h1>

        <p
          style={{
            margin: 0,
            maxWidth: isVertical ? "100%" : "58%",
            color: "rgba(226,232,240,0.74)",
            fontSize: subtitleSize,
            lineHeight: 1.35,
          }}
        >
          {subtitle}
        </p>
      </div>

      <div
        style={{
          position: "absolute",
          top: isVertical ? "54%" : "55%",
          left: isVertical ? "50%" : "58%",
          width: panelWidth,
          height: panelHeight,
          transform: `translate(-50%, -50%) scale(${interpolate(
            entrance,
            [0, 1],
            [0.9, 1]
          )})`,
          background: "rgba(8,13,24,0.78)",
          border: "1px solid rgba(34,211,238,0.28)",
          boxShadow: "0 0 34px rgba(34,211,238,0.12)",
          clipPath:
            "polygon(0 0, calc(100% - 22px) 0, 100% 22px, 100% 100%, 22px 100%, 0 calc(100% - 22px))",
          overflow: "hidden",
          padding: isVertical ? "76px 34px 34px" : "84px 46px 42px",
        }}
      >
        <div
          style={{
            position: "absolute",
            inset: 0,
            background:
              "linear-gradient(135deg, rgba(34,211,238,0.08), transparent 38%, rgba(250,204,21,0.06))",
          }}
        />

        <div
          style={{
            position: "absolute",
            top: 18,
            left: 22,
            right: 22,
            display: "flex",
            justifyContent: "space-between",
            alignItems: "center",
            zIndex: 3,
          }}
        >
          <div
            style={{
              color: primaryColor,
              fontSize: isVertical ? 15 : 16,
              fontWeight: 850,
              letterSpacing: 2,
              textTransform: "uppercase",
            }}
          >
            {panelLabel}
          </div>

          <div
            style={{
              padding: "7px 12px",
              border: `1px solid rgba(250,204,21,0.32)`,
              color: accentColor,
              background: "rgba(250,204,21,0.08)",
              fontSize: isVertical ? 13 : 14,
              fontWeight: 800,
              letterSpacing: 1.5,
              textTransform: "uppercase",
            }}
          >
            Média {Math.round(averageValue)}
            {unit}
          </div>
        </div>

        <div
          style={{
            position: "relative",
            zIndex: 2,
            display: "flex",
            flexDirection: "column",
            gap: isVertical ? 18 : 20,
            height: "100%",
            justifyContent: "center",
          }}
        >
          {data.map((item, index) => {
            const value = Math.max(0, Math.min(100, toNumber(item.value, 0)));
            const color = item.color || fallbackColors[index % fallbackColors.length];

            const labelOpacity = interpolate(
              frame,
              [index * 7, 8 + index * 7],
              [0, 1],
              {
                extrapolateLeft: "clamp",
                extrapolateRight: "clamp",
              }
            );

            const barProgress = interpolate(
              frame,
              [8 + index * 7, Math.min(animationDuration, 32 + index * 7)],
              [0, value],
              {
                extrapolateLeft: "clamp",
                extrapolateRight: "clamp",
              }
            );

            const markerPulse = 1 + Math.sin(frame / 8 + index) * 0.06;

            return (
              <div
                key={`progress-${index}`}
                style={{
                  opacity: labelOpacity,
                  display: "grid",
                  gridTemplateColumns: isVertical ? "1fr" : "180px 1fr 70px",
                  gap: isVertical ? 8 : 18,
                  alignItems: "center",
                  padding: isVertical ? "12px 12px" : "13px 14px",
                  background: "rgba(2,6,23,0.42)",
                  border: "1px solid rgba(34,211,238,0.12)",
                  clipPath:
                    "polygon(0 0, calc(100% - 10px) 0, 100% 10px, 100% 100%, 10px 100%, 0 calc(100% - 10px))",
                }}
              >
                <div
                  style={{
                    minWidth: 0,
                  }}
                >
                  <div
                    style={{
                      display: "flex",
                      alignItems: "center",
                      gap: 9,
                    }}
                  >
                    <div
                      style={{
                        width: 10,
                        height: 10,
                        background: color,
                        boxShadow: `0 0 12px ${color}`,
                        transform: `scale(${markerPulse})`,
                      }}
                    />

                    <div
                      style={{
                        color: "rgba(255,255,255,0.88)",
                        fontSize: isVertical ? 14 : 15,
                        fontWeight: 850,
                        letterSpacing: 1.3,
                        textTransform: "uppercase",
                        whiteSpace: "nowrap",
                        overflow: "hidden",
                        textOverflow: "ellipsis",
                      }}
                    >
                      {item.label}
                    </div>
                  </div>

                  {item.meta ? (
                    <div
                      style={{
                        marginTop: 4,
                        color: "rgba(34,211,238,0.58)",
                        fontSize: isVertical ? 10 : 11,
                        fontWeight: 700,
                        letterSpacing: 1,
                        textTransform: "uppercase",
                        whiteSpace: "nowrap",
                        overflow: "hidden",
                        textOverflow: "ellipsis",
                      }}
                    >
                      {item.meta}
                    </div>
                  ) : null}
                </div>

                <div
                  style={{
                    position: "relative",
                    height: isVertical ? 16 : 18,
                    background: "rgba(255,255,255,0.08)",
                    overflow: "hidden",
                    border: "1px solid rgba(34,211,238,0.15)",
                    boxShadow: "inset 0 0 18px rgba(2,6,23,0.72)",
                  }}
                >
                  <div
                    style={{
                      position: "absolute",
                      inset: 0,
                      backgroundImage:
                        "linear-gradient(90deg, rgba(255,255,255,0.06) 1px, transparent 1px)",
                      backgroundSize: "18px 100%",
                    }}
                  />

                  <div
                    style={{
                      width: `${barProgress}%`,
                      height: "100%",
                      background: `linear-gradient(90deg, ${secondaryColor}, ${color}, ${accentColor})`,
                      boxShadow: `0 0 18px ${color}`,
                    }}
                  />

                  <div
                    style={{
                      position: "absolute",
                      top: 0,
                      bottom: 0,
                      left: `${Math.min(100, barProgress)}%`,
                      width: 2,
                      background: accentColor,
                      opacity: barProgress > 2 ? 1 : 0,
                      boxShadow: `0 0 12px ${accentColor}`,
                    }}
                  />
                </div>

                <div
                  style={{
                    color: accentColor,
                    fontSize: isVertical ? 15 : 17,
                    fontWeight: 950,
                    letterSpacing: 1,
                    textAlign: isVertical ? "right" : "right",
                  }}
                >
                  {Math.round(barProgress)}
                  {unit}
                </div>
              </div>
            );
          })}
        </div>
      </div>

      <div
        style={{
          position: "absolute",
          left: isVertical ? 42 : 68,
          bottom: isVertical ? 56 : 54,
          right: isVertical ? 42 : undefined,
          width: isVertical ? "auto" : 560,
          padding: "18px 20px",
          borderLeft: `3px solid ${accentColor}`,
          background: "rgba(8,13,24,0.82)",
