              inset: 0,
              background: `
                radial-gradient(circle at center, transparent 0%, rgba(2,6,23,0.12) 46%, rgba(2,6,23,0.78) 100%),
                linear-gradient(135deg, rgba(34,211,238,0.08), transparent 44%, rgba(250,204,21,0.1))
