                "polygon(0 0, calc(100% - 12px) 0, 100% 12px, 100% 100%, 12px 100%, 0 calc(100% - 12px))",
            }}
          />

          <div
            style={{
              position: "absolute",
              left: "50%",
              top: "50%",
              width: activePipWidth * 0.48,
              height: activePipWidth * 0.48,
              border: `1px dashed ${primaryColor}55`,
              borderRadius: "50%",
              transform: `translate(-50%, -50%) rotate(${orbitRotation}deg)`,
              opacity: 0.72,
            }}
          />

          <div
            style={{
              position: "absolute",
              left: "50%",
              top: "50%",
              width: activePipWidth * 0.28,
              height: activePipWidth * 0.28,
              border: `1px solid ${accentColor}55`,
              borderRadius: "50%",
              transform: `translate(-50%, -50%) rotate(${counterOrbitRotation}deg)`,
              opacity: 0.72,
            }}
          />

{pipTag ? (          <div
            style={{
              position: "absolute",
              top: 10,
              left: 10,
              display: "inline-flex",
              alignItems: "center",
              gap: 8,
              padding: "6px 9px",
              background: "rgba(2,6,23,0.74)",
              border: `1px solid ${accentColor}55`,
              color: accentColor,
