              zIndex: 3,
            }}
          >
            <span
              style={{
                width: 6,
                height: 6,
                background: accentColor,
                boxShadow: `0 0 10px ${accentColor}`,
              }}
            />
            {pipTag}
          </div>) : null}



{(pipTitle || pipSubtitle || coordinateText || distanceText) ? (          <div
            style={{
              position: "absolute",
              left: 14,
              right: 14,
              bottom: 14,
              zIndex: 4,
            }}
          >
            <h2
              style={{
                margin: 0,
                color: textColor,
                fontSize: pipTitleSize,
                fontWeight: 950,
